"use strict";(globalThis.webpackChunkdocs=globalThis.webpackChunkdocs||[]).push([[4027],{7855(e,t,r){r.r(t),r.d(t,{assets:()=>h,contentTitle:()=>i,default:()=>c,frontMatter:()=>o,metadata:()=>n,toc:()=>d});const n=JSON.parse('{"id":"guide-for-users/why-targets-exist","title":"Why targets exist","description":"What a target curve represents, why \\"flat\\" is not the goal, and how Harman, Diffuse Field, and reviewer targets differ.","source":"@site/docs/guide-for-users/04-why-targets-exist.mdx","sourceDirName":"guide-for-users","slug":"/guide-for-users/why-targets-exist","permalink":"/modernGraphTool/docs/ko/guide-for-users/why-targets-exist","draft":false,"unlisted":false,"editUrl":"https://github.com/potatosalad775/modernGraphTool/tree/main/docs/docs/guide-for-users/04-why-targets-exist.mdx","tags":[],"version":"current","sidebarPosition":4,"frontMatter":{"sidebar_position":4,"description":"What a target curve represents, why \\"flat\\" is not the goal, and how Harman, Diffuse Field, and reviewer targets differ."},"sidebar":"tutorialSidebar","previous":{"title":"How measurements work","permalink":"/modernGraphTool/docs/ko/guide-for-users/how-measurements-work"},"next":{"title":"Interface tour","permalink":"/modernGraphTool/docs/ko/guide-for-users/interface-tour"}}');var a=r(4848),s=r(8453);const o={sidebar_position:4,description:'What a target curve represents, why "flat" is not the goal, and how Harman, Diffuse Field, and reviewer targets differ.'},i="Why targets exist",h={},d=[{value:"Flat is not the goal",id:"flat-is-not-the-goal",level:2},{value:"What a target is",id:"what-a-target-is",level:2},{value:"Different targets, different philosophies",id:"different-targets-different-philosophies",level:2},{value:"Nobody agrees, and that&#39;s fine",id:"nobody-agrees-and-thats-fine",level:2},{value:"A range, not a line",id:"a-range-not-a-line",level:2}];function l(e){const t={a:"a",admonition:"admonition",em:"em",h1:"h1",h2:"h2",header:"header",hr:"hr",li:"li",p:"p",strong:"strong",ul:"ul",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"why-targets-exist",children:"Why targets exist"})}),"\n",(0,a.jsxs)(t.p,{children:["The last page explained where a curve comes from and that what you see is raw SPL from the measurement rig. This page explains the dotted line drawn ",(0,a.jsx)(t.em,{children:"across"})," that curve \u2014 the ",(0,a.jsx)(t.strong,{children:"target"})," \u2014 and why it's the thing that turns a raw curve into a meaningful judgment."]}),"\n",(0,a.jsx)(t.p,{children:'Targets trip up newcomers because the obvious expectation is wrong. Most people assume that a "good" headphone should measure as a flat line: equal loudness at every frequency. That sounds intuitive \u2014 and it\'s completely wrong, for two reasons stacked on top of each other.'}),"\n",(0,a.jsx)(t.h2,{id:"flat-is-not-the-goal",children:"Flat is not the goal"}),"\n",(0,a.jsxs)(t.p,{children:["First reason: even if you could play a perfectly flat signal straight to your eardrum, you'd hate it. It would sound ",(0,a.jsx)(t.strong,{children:"thin, shouty, and treble-heavy"}),'. No bass to speak of, a hard upper midrange, and sibilant highs. Nobody who\'s actually listened to a "flat" headphone calls it neutral.']}),"\n",(0,a.jsx)(t.p,{children:"The reason is that your own anatomy isn't flat. When you listen to a real speaker in a real room, the sound bounces off your shoulders, squeezes through your outer ear's folds, and travels down a curved canal before reaching your eardrum. By the time it arrives, your head has already added a broad boost around 2\u20134 kHz, a bit of low-end reinforcement, and a roll-off at the very top. Everything you've ever heard in your life has been pre-shaped by that filtering, so \"neutral\" to a human ear does not look flat."}),"\n",(0,a.jsxs)(t.p,{children:["Second reason: the curve on screen isn't ",(0,a.jsx)(t.em,{children:"at your eardrum"})," anyway \u2014 it's at the ",(0,a.jsx)(t.strong,{children:"rig's microphone"}),". That rig has its own canal, its own eardrum simulator, its own natural resonances. A headphone that sounds a specific way to your ears will raw-measure on that rig as a ",(0,a.jsx)(t.em,{children:"specific bumpy shape"})," \u2014 the rig's own house curve plus whatever that sound translates to on that rig's mic."]}),"\n",(0,a.jsxs)(t.p,{children:["A ",(0,a.jsx)(t.strong,{children:"target"})," is a pre-computed version of exactly that shape. It's the line that says ",(0,a.jsx)(t.em,{children:'"this is what a headphone needs to look like on this specific rig in order to sound the way I\'ve defined as good"'}),'. Different targets encode different definitions of "good" \u2014 more on that in a moment. You don\'t need to do any translation in your head; the target does it for you, and you just look at how close the measurement sits to the target line.']}),"\n",(0,a.jsx)(t.h2,{id:"what-a-target-is",children:"What a target is"}),"\n",(0,a.jsx)(t.p,{children:"In modernGraphTool, a target is exactly the same kind of file as a headphone measurement: a line on the graph. The difference is what it represents:"}),"\n",(0,a.jsxs)(t.ul,{children:["\n",(0,a.jsxs)(t.li,{children:["A ",(0,a.jsx)(t.strong,{children:"headphone curve"})," is a real measurement \u2014 raw SPL from the rig's mic for one specific headphone."]}),"\n",(0,a.jsxs)(t.li,{children:["A ",(0,a.jsx)(t.strong,{children:"target curve"}),' is a reference line designed for a specific rig, representing the raw shape a headphone is expected to measure on that rig in order to sound like whatever the target\'s author defines as "right".']}),"\n"]}),"\n",(0,a.jsxs)(t.p,{children:["When you overlay a target on a headphone curve, you're asking: ",(0,a.jsx)(t.em,{children:"how close does this headphone come to the reference encoded in this target, on this rig?"})," The answer is the vertical distance between the two lines at each frequency. A headphone ",(0,a.jsx)(t.em,{children:"on the target"})," matches whatever the target represents. Anywhere they differ is where the headphone departs from that particular reference \u2014 brighter, warmer, bassier, whatever."]}),"\n",(0,a.jsxs)(t.p,{children:["What the target ",(0,a.jsx)(t.em,{children:"represents"})," depends on which target you loaded, and those definitions don't agree with each other. That's not a bug. The next section explains the main families you'll encounter."]}),"\n",(0,a.jsx)(t.admonition,{title:"Use the target that matches the rig",type:"info",children:(0,a.jsx)(t.p,{children:"Targets are rig-specific by design. A Harman IE target drawn for a 711-style rig is a different file than a Harman IE target drawn for a B&K 5128 rig. The site operator picks the targets that match the rig in use, which is part of why each deployment ships its own target list. Don't overlay a target from one rig onto a measurement from a different rig \u2014 the shapes won't line up, and the comparison will mislead you."})}),"\n",(0,a.jsx)(t.h2,{id:"different-targets-different-philosophies",children:"Different targets, different philosophies"}),"\n",(0,a.jsx)(t.p,{children:"You'll see several target curves available in modernGraphTool, and they don't agree with each other. That's on purpose \u2014 they're answering different questions. Broadly there are two camps:"}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.strong,{children:"Neutrality targets"})," try to describe how a headphone should measure to sound ",(0,a.jsx)(t.em,{children:"tonally neutral"}),' to a human listener \u2014 no deliberate bass boost, no treble sweetening, just the shape that corresponds to "nothing stands out".']}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.strong,{children:"Preference targets"})," describe how a headphone should measure to sound ",(0,a.jsx)(t.em,{children:"enjoyable"})," according to some listening panel or individual reviewer \u2014 often with a deliberate bass lift, a shaped upper midrange, and gentler treble than strict neutrality. They're not claiming to be neutral; they're claiming to be ",(0,a.jsx)(t.em,{children:"liked"}),"."]}),"\n",(0,a.jsx)(t.p,{children:"Here are the families of targets you're most likely to encounter:"}),"\n",(0,a.jsxs)(t.ul,{children:["\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"Diffuse Field (DF)"})," \u2014 A ",(0,a.jsx)(t.strong,{children:"neutrality target"})," rooted in an older academic model: what you'd hear from a loudspeaker in a highly reflective room, averaged across all incoming directions. It's the closest thing in common use to \"tonally neutral at the eardrum\", and is often used as a reference baseline."]}),"\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"Free Field"})," \u2014 Another neutrality-flavored target, based on a single speaker in front of you in an anechoic (non-reflective) environment. Less common than DF."]}),"\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"Harman OE / IE"})," \u2014 ",(0,a.jsx)(t.strong,{children:"Preference targets"})," derived from a large blind-listening study run by Harman (the company that owns JBL, AKG, and others). Listeners were asked to EQ headphones until they sounded ",(0,a.jsx)(t.em,{children:"best to them"}),', and the results were averaged. The Harman curves have deliberately boosted bass and a shaped upper midrange \u2014 they represent "what most people enjoy", not "what measures as neutral". Also available in dated revisions (2013, 2015, 2018) as the research evolved.']}),"\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"Reviewer preference curves"})," \u2014 Some measurement sites publish their own preferred target based on the operator's listening taste and experience. These are honest statements of one person's preference. They're not neutrality claims and shouldn't be read as such."]}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"Which is \"right\"? None of them, not universally. A neutrality target tells you where a headphone stands vs tonal neutrality. A preference target tells you where it stands vs a specific definition of enjoyable. They're different questions; picking the wrong one doesn't make the graph lie, but it can make you draw the wrong conclusion. Most people end up keeping one neutrality reference (usually DF) and one preference reference (usually Harman or a reviewer's curve) and comparing headphones against both."}),"\n",(0,a.jsx)(t.h2,{id:"nobody-agrees-and-thats-fine",children:"Nobody agrees, and that's fine"}),"\n",(0,a.jsxs)(t.p,{children:["If you load five different targets on the same graph, they'll be visibly different. Some are brighter, some are warmer, some have more bass. That's not a sign that the measurement industry is broken \u2014 it's a reminder that ",(0,a.jsx)(t.strong,{children:'"good sound" covers at least two different questions'})," (is it neutral, is it enjoyable) and reasonable people picking different listener panels, different rigs, and different definitions will arrive at different curves."]}),"\n",(0,a.jsx)(t.p,{children:"modernGraphTool lets site operators configure which targets appear in the list, which means different deployments ship different lineups. If you bookmark two different measurement sites, don't be surprised if the available targets are different."}),"\n",(0,a.jsx)(t.h2,{id:"a-range-not-a-line",children:"A range, not a line"}),"\n",(0,a.jsxs)(t.p,{children:["One last idea before we get into the buttons. Preference research also shows that there isn't a single \"correct\" curve \u2014 there's a ",(0,a.jsx)(t.strong,{children:"range"}),". Most listeners tolerate a few dB of variation in bass and treble around whatever they consider neutral, so a headphone doesn't have to hit the target line exactly to sound great; it just needs to stay inside the acceptable band."]}),"\n",(0,a.jsxs)(t.p,{children:["The tool can draw that band as a shaded region on top of the graph. It's called the ",(0,a.jsx)(t.strong,{children:"preference bound"}),", and it's explained alongside the target customizer on ",(0,a.jsx)(t.a,{href:"/modernGraphTool/docs/ko/guide-for-users/targets-and-preferences",children:"Targets and preferences"}),", with the deep dive at ",(0,a.jsx)(t.a,{href:"../features/preference-bound",children:"Preference Bound"}),"."]}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsxs)(t.p,{children:["That's the last of the concept pages. From here on the guide is about the actual interface \u2014 starting with ",(0,a.jsx)(t.a,{href:"/modernGraphTool/docs/ko/guide-for-users/interface-tour",children:"Interface tour"}),"."]})]})}function c(e={}){const{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(l,{...e})}):l(e)}},8453(e,t,r){r.d(t,{R:()=>o,x:()=>i});var n=r(6540);const a={},s=n.createContext(a);function o(e){const t=n.useContext(s);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function i(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:o(e.components),n.createElement(s.Provider,{value:t},e.children)}}}]);